+pub unsafe fn sys_arch_prctl(code: i32, addr: usize) -> Result<(), i32> {
+    let ret = unsafe { raw::syscall2(SYS_ARCH_PRCTL, code as usize, addr) };
+    syscall_result(ret).map(|_| ())
+}
